body:
_What are the reasons/motivation for this change?_

#4590

_Explain how this is achieved._

If all the (non-select) inputs of a `$_MUX{4,8,16}_` are undefined, replace it, just like we do for `$mux` and `$_MUX_`. Add `tests/opt/opt_expr_mux_undef.ys` to verify this.

This doesn't do any const folding on the wide muxes, or shrinking to less wide muxes.  It only handles the case where all inputs are 'x and the mux can be completely removed.

_If applicable, please suggest to reviewers how they can test the change._

The following script (from https://github.com/YosysHQ/yosys/issues/4590#issuecomment-2766390391) fails without this patch, and passes with it.

```
read_verilog << EOT
module top (
	input  clk,
	output [7:0] rddata
);

  reg [31:0] index;

  always @(posedge clk)
    index <= index + 1;
  initial
    index = 32'b0;

  reg [7:0] rom[33:0];
  initial begin
    rom[33] = 8'b00000000;
    rom[32] = 8'b00000001;
    rom[31] = 8'b00000010;
    rom[30] = 8'b00000011;
    rom[29] = 8'b00000100;
    rom[28] = 8'b00000101;
    rom[27] = 8'b00000110;
    rom[26] = 8'b00000111;
    rom[25] = 8'b00001000;
    rom[24] = 8'b00001001;
    rom[23] = 8'b00001010;
    rom[22] = 8'b00001011;
    rom[21] = 8'b00001100;
    rom[20] = 8'b00001101;
    rom[19] = 8'b00001110;
    rom[18] = 8'b00001111;
    rom[17] = 8'b00010000;
    rom[16] = 8'b00010001;
    rom[15] = 8'b00010010;
    rom[14] = 8'b00010011;
    rom[13] = 8'b00010100;
    rom[12] = 8'b00010101;
    rom[11] = 8'b00010110;
    rom[10] = 8'b00010111;
    rom[ 9] = 8'b00011000;
    rom[ 8] = 8'b00011001;
    rom[ 7] = 8'b00011010;
    rom[ 6] = 8'b00011011;
    rom[ 5] = 8'b00011100;
    rom[ 4] = 8'b00011101;
    rom[ 3] = 8'b00011110;
    rom[ 2] = 8'b00011111;
    rom[ 1] = 8'b00100000;
    rom[ 0] = 8'b00100001;
    end

  assign rddata = rom[index];

endmodule
EOT
synth_xilinx -arch xc7 -top top -widemux 5
```
